var builder = WebApplication.CreateBuilder(args);
builder.Services.AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "HttpMcpServer", Version = "1.0.0" };
        options.ServerInstructions = "An HTTP MCP server exposing tools and configuration resources.";
    })
