using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes a message back to the caller.")]
    public static string Echo(
        [Description("The message to echo")] string message) =>
        $"Echo: {message}";

    [McpServerTool, Description("Adds two numbers and returns the result.")]
    public static string Add(
        [Description("First number")] double a,
        [Description("Second number")] double b) =>
        $"{a} + {b} = {a + b}";
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(UriTemplate = "config://app", Name = "App Config",
        MimeType = "application/json"),
     Description("Returns the current application configuration.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        }, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(UriTemplate = "config://version", Name = "Version Info",
        MimeType = "application/json"),
     Description("Returns server version information.")]
    public static string GetVersionInfo() =>
        JsonSerializer.Serialize(new
        {
            Version = "1.0.0",
            BuildDate = "2026-04-24",
            Runtime = System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription
        }, new JsonSerializerOptions { WriteIndented = true });
}

